const body = $input.first().json.body;
const message = body.message || '';
const date = body.date || '';

// Ver si es un comando para enviar recordatorios
const isReminder = message.toLowerCase().includes('send') || message.toLowerCase().includes('remind');

// Si no es un recordatorio general, buscamos un nombre de barbero/cliente
let searchName = '';
if (!isReminder) {
  const words = message.split(' ');
  const nameWords = words.filter(w => w.length > 2 && w[0] === w[0].toUpperCase() && isNaN(w[0]));
  searchName = nameWords.join(' ');
}

return [{
  json: {
    date,
    message,
    searchName,
    isReminder, 
    queryDate: date
  }
}];

const apiResponse = $input.first().json.data || $input.first().json;
const searchName = $('Code in JavaScript').first().json.searchName || '';
const isReminder = $('Code in JavaScript').first().json.isReminder || false;

let answer = "";

// Filtrar
const matchingAppointments = apiResponse.filter(apt => {
  if (isReminder || !searchName) return true; // Si son recordatorios, traemos TODO lo de ese día
  return apt.customerName.toLowerCase().includes(searchName.toLowerCase()) || 
         (apt.barberId && apt.barberId.name && apt.barberId.name.toLowerCase().includes(searchName.toLowerCase()));
});

if (matchingAppointments.length === 0) {
  answer = "No appointments found for the requested criteria.";
} 
else if (isReminder) {
  // B: Enviar recordatorios
  answer = "Reminders sent successfully for today's appointments:\n";
  matchingAppointments.forEach(apt => {
    const time = apt.start.split(' ')[1] || apt.start;
    const barberName = apt.barberId?.name || 'Unknown barber';
    answer += `- SMS sent to ${apt.customerName} (${apt.customerPhone}): "Hi ${apt.customerName}, you have an appointment with ${barberName} at ${time}. See you soon!"\n`;
  });
} 
else {
  // A: Lista concisa
  answer = "Here is the list of appointments:\n";
  matchingAppointments.forEach(apt => {
    const time = apt.start.split(' ')[1] || apt.start;
    const barberName = apt.barberId?.name || 'Unknown barber';
    answer += `- ${time} | Customer: ${apt.customerName} | Barber: ${barberName}\n`;
  });
}

return [{
  json: {
    reply: answer,
    actionTaken: isReminder ? 'sent_reminders' : 'listed_appointments'
  }
}];
